mapper.select:
SELECT DATE(updated_at) as date, COUNT(*) as count FROM tasks
WHERE author = #{userId} AND status = 'completed' AND updated_at >= #{since}
GROUP BY DATE(updated_at) ORDER BY date

SELECT DATE(start_time) as date, SUM(actual_minutes) as minutes FROM pomodoro_sessions
WHERE user_id = #{userId} AND status = 'completed' AND start_time >= #{since} AND start_time <= #{end}
GROUP BY DATE(start_time) ORDER BY date
